package com.example.security.error;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.ControllerAdvice;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.context.request.WebRequest;
import org.springframework.web.servlet.mvc.method.annotation.ResponseEntityExceptionHandler;

import java.time.LocalDateTime;
import java.util.HashMap;
import java.util.Map;
import java.util.UUID;

/**
 * Global exception handler for all REST controllers.
 * Sanitizes error responses and prevents information disclosure.
 */
@ControllerAdvice
public class GlobalExceptionHandler extends ResponseEntityExceptionHandler {

    private static final Logger log = LoggerFactory.getLogger(GlobalExceptionHandler.class);

    /**
     * Handles all uncaught exceptions with sanitized response.
     */
    @ExceptionHandler(Exception.class)
    public ResponseEntity<Map<String, Object>> handleGlobalException(
            Exception ex, 
            WebRequest request) {

        // Generate unique error reference ID for correlation
        String errorId = UUID.randomUUID().toString();

        // Log full details internally with error ID
        log.error("[Error ID: {}] Unhandled exception occurred: {}", 
                errorId, ex.getMessage(), ex);

        // Return sanitized response to client
        Map<String, Object> errorResponse = new HashMap<>();
        errorResponse.put("timestamp", LocalDateTime.now());
        errorResponse.put("status", HttpStatus.INTERNAL_SERVER_ERROR.value());
        errorResponse.put("error", "Internal Server Error");
        errorResponse.put("message", "An unexpected error occurred. Please contact support with reference ID: " + errorId);
        errorResponse.put("reference", errorId);
        errorResponse.put("path", request.getDescription(false).replace("uri=", ""));

        return new ResponseEntity<>(errorResponse, HttpStatus.INTERNAL_SERVER_ERROR);
    }

    /**
     * Handles validation exceptions (400 Bad Request).
     */
    @ExceptionHandler(IllegalArgumentException.class)
    public ResponseEntity<Map<String, Object>> handleValidationException(
            IllegalArgumentException ex,
            WebRequest request) {

        String errorId = UUID.randomUUID().toString();
        log.warn("[Error ID: {}] Validation error: {}", errorId, ex.getMessage());

        Map<String, Object> errorResponse = new HashMap<>();
        errorResponse.put("timestamp", LocalDateTime.now());
        errorResponse.put("status", HttpStatus.BAD_REQUEST.value());
        errorResponse.put("error", "Bad Request");
        errorResponse.put("message", "Invalid input provided");
        errorResponse.put("reference", errorId);

        return new ResponseEntity<>(errorResponse, HttpStatus.BAD_REQUEST);
    }
}

/**
 * Configure application.yml for production:
 */
// application-prod.yml
/*
server:
  error:
    include-message: never
    include-binding-errors: never
    include-stacktrace: never
    include-exception: false

spring:
  mvc:
    throw-exception-if-no-handler-found: true
  web:
    resources:
      add-mappings: false

logging:
  level:
    root: WARN
    com.example: INFO
  pattern:
    console: "%d{yyyy-MM-dd HH:mm:ss} - %msg%n"
*/

const express = require('express');
const helmet = require('helmet');
const { v4: uuidv4 } = require('uuid');
const winston = require('winston');

const app = express();

// Configure structured logging
const logger = winston.createLogger({
  level: process.env.LOG_LEVEL || 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  transports: [
    new winston.transports.File({ filename: 'error.log', level: 'error' }),
    new winston.transports.File({ filename: 'combined.log' })
  ]
});

if (process.env.NODE_ENV !== 'production') {
  logger.add(new winston.transports.Console({
    format: winston.format.simple()
  }));
}

// Security middleware - must be early in chain
app.use(helmet({
  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"],
      scriptSrc: ["'self'"]
    }
  },
  hsts: {
    maxAge: 31536000,
    includeSubDomains: true,
    preload: true
  }
}));

app.use(express.json());

// Request ID middleware for error correlation
app.use((req, res, next) => {
  req.id = uuidv4();
  res.setHeader('X-Request-ID', req.id);
  next();
});

// Your routes here
app.get('/api/users/:id', async (req, res, next) => {
  try {
    // Simulate database error
    throw new Error('Database connection failed: Timeout connecting to postgres://prod-db:5432/users');
  } catch (error) {
    next(error); // Pass to error handler
  }
});

// 404 Handler (must be after all routes)
app.use((req, res, next) => {
  res.status(404).json({
    status: 404,
    error: 'Not Found',
    message: 'The requested resource was not found',
    path: req.path,
    timestamp: new Date().toISOString()
  });
});

// Global Error Handler (must be last middleware)
app.use((err, req, res, next) => {
  const errorId = req.id || uuidv4();

  // Log full error details internally
  logger.error({
    errorId,
    message: err.message,
    stack: err.stack,
    url: req.url,
    method: req.method,
    ip: req.ip,
    userAgent: req.get('user-agent')
  });

  // Determine status code
  const statusCode = err.statusCode || err.status || 500;

  // Production: Send sanitized error
  if (process.env.NODE_ENV === 'production') {
    return res.status(statusCode).json({
      status: statusCode,
      error: statusCode === 500 ? 'Internal Server Error' : 'Error',
      message: statusCode === 500 
        ? `An unexpected error occurred. Reference ID: ${errorId}`
        : 'An error occurred processing your request',
      reference: errorId,
      timestamp: new Date().toISOString()
    });
  }

  // Development: Include stack trace (never in production)
  res.status(statusCode).json({
    status: statusCode,
    error: err.name || 'Error',
    message: err.message,
    stack: err.stack, // Only in development
    reference: errorId,
    timestamp: new Date().toISOString()
  });
});

// Ensure NODE_ENV is set correctly
if (!process.env.NODE_ENV) {
  console.error('WARNING: NODE_ENV not set. Defaulting to development mode.');
  process.env.NODE_ENV = 'development';
}

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  logger.info(`Server running on port ${PORT} in ${process.env.NODE_ENV} mode`);
});

module.exports = app;
